import React from 'react';
import PropTypes from 'prop-types';
import styled from 'styled-components';
import { Layout, About, Jobs, Featured, HomeBlogPreview, Contact } from '@components';
import { socialMedia } from '@config';
import { Icon } from '@components/icons';

const StyledHomePage = styled.main`
  position: relative;
  isolation: isolate;
  width: 100%;
  margin: 0 auto;
  padding: 136px 90px 72px;
  max-width: none;
  min-height: 100vh;
  color: var(--slate);
  background: transparent;

  @media (max-width: 1080px) {
    padding: 124px 70px 60px;
  }

  @media (max-width: 900px) {
    padding: 112px 42px 48px;
  }

  @media (max-width: 480px) {
    padding: 100px 24px 36px;
  }

  .numbered-heading {
    color: var(--lightest-slate);
  }
`;

const StyledHomeGrid = styled.div`
  position: relative;
  z-index: 1;
  display: grid;
  width: 100%;
  max-width: 1180px;
  margin: 0 auto;
  grid-template-columns: minmax(260px, 340px) minmax(0, 1fr);
  gap: 72px;
  align-items: start;

  @media (max-width: 1080px) {
    gap: 56px;
    grid-template-columns: minmax(240px, 300px) minmax(0, 1fr);
  }

  @media (max-width: 900px) {
    grid-template-columns: 1fr;
    gap: 38px;
  }
`;

const StyledSidebar = styled.aside`
  position: sticky;
  top: 112px;
  align-self: start;
  padding: 10px 0 40px;

  @media (max-width: 1080px) {
    top: 96px;
  }

  @media (max-width: 900px) {
    position: static;
    padding-bottom: 0;
  }
`;

const StyledIntro = styled.div`
  .eyebrow {
    color: var(--green);
    font-family: var(--font-ui);
    font-size: var(--fz-sm);
    font-weight: 600;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    margin-bottom: 16px;
  }

  h1 {
    margin: 0;
    font-size: clamp(48px, 5vw, 72px);
    line-height: 0.94;
    letter-spacing: -0.05em;
  }

  .role {
    margin-top: 12px;
    color: var(--dark-slate);
    font-size: clamp(18px, 2.1vw, 23px);
    font-weight: 500;
  }

  .summary {
    margin-top: 18px;
    max-width: 32ch;
    color: var(--slate);
    font-size: var(--fz-md);
    line-height: 1.8;
  }
`;

const StyledSocialRow = styled.ul`
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 0;
  margin: 52px 0 0;
  list-style: none;

  @media (min-width: 901px) {
    margin-top: min(22vh, 180px);
  }

  a {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 40px;
    height: 40px;
    border-radius: 999px;
    color: var(--light-slate);
    background-color: rgba(255, 255, 255, 0.62);
    border: 1px solid var(--lightest-navy);
    box-shadow: 0 10px 24px -18px var(--navy-shadow);
    transition: var(--transition);
  }

  a:hover,
  a:focus {
    color: var(--green);
    background-color: var(--green-tint);
    transform: translateY(-2px);
  }

  svg {
    width: 18px;
    height: 18px;
  }
`;

const StyledContent = styled.div`
  min-width: 0;

  section {
    margin: 0;
    max-width: 100%;
    scroll-margin-top: 90px;
  }

  section + section {
    margin-top: 80px;
  }

  section:not(:first-of-type) {
    padding-top: 28px;
    border-top: 1px solid var(--lightest-navy);
  }

  @media (max-width: 900px) {
    section + section {
      margin-top: 60px;
    }
  }
`;

const IndexPage = ({ location }) => {
  return (
    <Layout location={location}>
      <StyledHomePage>
        <StyledHomeGrid>
          <StyledSidebar>
            <StyledIntro>
              <div className="eyebrow">Software Engineer</div>
              <h1>Robin Lee.</h1>
              <div className="role">I build reliable backend systems at scale.</div>
              <p className="summary">
                I specialize in cloud-native services, event-driven architecture, and automation that helps teams
                ship faster with confidence.
              </p>
            </StyledIntro>

            <StyledSocialRow aria-label="Social links">
              {socialMedia.map(({ url, name }) => (
                <li key={name}>
                  <a href={url} aria-label={name} target="_blank" rel="noopener noreferrer">
                    <Icon name={name} />
                  </a>
                </li>
              ))}
            </StyledSocialRow>
          </StyledSidebar>

          <StyledContent>
            <About />
            <Jobs />
            <Featured />
            <HomeBlogPreview />
            <Contact />
          </StyledContent>
        </StyledHomeGrid>
      </StyledHomePage>
    </Layout>
  );
};

IndexPage.propTypes = {
  location: PropTypes.object.isRequired,
};

export default IndexPage;
